// tests/selectors.test.ts
import assert from "node:assert/strict";
import test from "node:test";

// src/lib/selectors.ts
function formatDocumentEvidencePages(evidence) {
  const ranges = evidence.map((item) => {
    if (typeof item.pageStart !== "number" && typeof item.pageEnd !== "number") {
      return null;
    }
    const start = item.pageStart ?? item.pageEnd;
    const end = item.pageEnd ?? item.pageStart;
    if (typeof start !== "number" || typeof end !== "number") {
      return null;
    }
    return {
      start: Math.min(start, end),
      end: Math.max(start, end)
    };
  }).filter((range) => range !== null).sort((left, right) => left.start - right.start || left.end - right.end);
  const uniqueRanges = ranges.filter(
    (range, index) => index === 0 || range.start !== ranges[index - 1].start || range.end !== ranges[index - 1].end
  );
  if (uniqueRanges.length === 0) {
    return "No page marker";
  }
  const pages = uniqueRanges.map((range) => range.start === range.end ? `${range.start}` : `${range.start}-${range.end}`);
  return `${uniqueRanges.length === 1 && uniqueRanges[0].start === uniqueRanges[0].end ? "Page" : "Pages"} ${pages.join(", ")}`;
}

// tests/selectors.test.ts
test("formatDocumentEvidencePages separates distinct page citations", () => {
  assert.equal(
    formatDocumentEvidencePages([
      { quote: "Debt-to-GDP ratio", pageStart: 33, pageEnd: 33 },
      { quote: "Debt-to-GDP ratio", pageStart: 167, pageEnd: 167 }
    ]),
    "Pages 33, 167"
  );
});
test("formatDocumentEvidencePages preserves actual page ranges", () => {
  assert.equal(
    formatDocumentEvidencePages([
      { quote: "First span", pageStart: 33, pageEnd: 35 },
      { quote: "Second span", pageStart: 167, pageEnd: 168 }
    ]),
    "Pages 33-35, 167-168"
  );
});
test("formatDocumentEvidencePages handles single pages and missing markers", () => {
  assert.equal(formatDocumentEvidencePages([{ quote: "Only page", pageStart: 33, pageEnd: 33 }]), "Page 33");
  assert.equal(formatDocumentEvidencePages([{ quote: "No marker", pageStart: null, pageEnd: null }]), "No page marker");
});
